    int64_t idx = indices[row];
    T* out_ptr = output + row * embed_dim;

    int64_t col_start = (int64_t)blockIdx.x * blockDim.x + threadIdx.x;
    int64_t stride = (int64_t)gridDim.x * blockDim.x;

    if (idx < 0 || idx >= num_embeddings) {
        for (int64_t c = col_start; c < embed_dim; c += stride) {
            out_ptr[c] = T(0);
        }
        return;
