#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <torch/extension.h>

// Tiled GEMM kernel for bfloat16: computes output[m, n] = sum_k input[m, k] * weight[n, k]
// input: [M, K] row-major
// weight: [N, K] row-major (so weight^T is [K, N])
// output: [M, N] row-major

#define TILE 32

__global__ void linear_bf16_kernel(
    const __nv_bfloat16* __restrict__ input,
    const __nv_bfloat16* __restrict__ weight,
    __nv_bfloat16* __restrict__ output,
    int M, int N, int K)
{
    __shared__ __nv_bfloat16 As[TILE][TILE];
    __shared__ __nv_bfloat16 Bs[TILE][TILE];

    int row = blockIdx.y * TILE + threadIdx.y; // M dim
    int col = blockIdx.x * TILE + threadIdx.x; // N dim

    float acc = 0.0f;

    int numTiles = (K + TILE - 1) / TILE;

    for (int t = 0; t < numTiles; ++t) {
        int k_idx_a = t * TILE + threadIdx.x;
        int k_idx_b = t * TILE + threadIdx.y;

        if (row < M && k_idx_a < K) {
            As[threadIdx.y][threadIdx.x] = input[row * K + k_idx_a];
        } else {
            As[threadIdx.y][threadIdx.x] = __float2bfloat16(0.0f);
        }

        // weight[col, k_idx_b] -- we want Bs[k][n] but store as [threadIdx.y][threadIdx.x] = weight[col, k_idx_b]
        // where threadIdx.y corresponds to k, threadIdx.x corresponds to n
        if (col < N && k_idx_b < K) {
            Bs[threadIdx.y][threadIdx.x] = weight[col * K + k_idx_b];
        } else {
            Bs[threadIdx.y][threadIdx.x] = __float2bfloat16(0.0f);
        }

        __syncthreads();

        #pragma unroll
        for (int k = 0; k < TILE; ++k) {
            acc += __bfloat162float(As[threadIdx.y][k]) * __bfloat162float(Bs[k][threadIdx.x]);
        }

        __syncthreads();
    }

    if (row < M && col < N) {
        output[row * N + col] = __float2bfloat16(acc);
    }
}

torch::Tensor launch(torch::Tensor input, torch::Tensor weight, c10::optional<torch::Tensor> bias) {
    TORCH_CHECK(input.is_cuda(), "input must be CUDA");
    TORCH_CHECK(weight.is_cuda(), "weight must be CUDA");
    TORCH_CHECK(input.is_contiguous(), "input must be contiguous");
    TORCH_CHECK(weight.is_contiguous(), "weight must be contiguous");
    TORCH_CHECK(input.scalar_type() == at::kBFloat16, "input must be bfloat16");
    TORCH_CHECK(weight.scalar_type() == at::kBFloat16, "weight must be bfloat16");
    TORCH_CHECK(weight.dim() == 2, "weight must be 2D");

    int64_t K = weight.size(1);
    int64_t N = weight.size(0);

    // Output shape: input.shape[:-1] + (N,)
    auto in_sizes = input.sizes().vec();
    TORCH_CHECK(in_sizes.back() == K, "input last dim must match weight's K");

    int64_t M = 1;
    for (size_t i = 0; i < in_sizes.size() - 1; ++i) M *= in_sizes[i];

    auto out_sizes = in_sizes;
    out_sizes.back() = N;

    auto output = torch::empty(out_sizes, input.options());

    dim3 block(TILE, TILE);
    dim3 grid((N + TILE - 1) / TILE, (M + TILE - 1) / TILE);

    linear_bf16_kernel<<<grid, block>>>(
        reinterpret_cast<const __nv_bfloat16*>(input.data_ptr()),
        reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr()),
        reinterpret_cast<__nv_bfloat16*>(output.data_ptr()),
        (int)M, (int)N, (int)K
    );

    if (bias.has_value() && bias.value().defined()) {
        output.add_(bias.value());
    }

    return output;
}

