#define WARP_SIZE 32

__inline__ __device__ float warp_reduce_max(float v) {
    for (int off = WARP_SIZE / 2; off > 0; off >>= 1) {
        float o = __shfl_xor_sync(0xffffffff, v, off);
        v = fmaxf(v, o);
    }
    return v;
}

__inline__ __device__ float warp_reduce_sum(float v) {
    for (int off = WARP_SIZE / 2; off > 0; off >>= 1) {
        v += __shfl_xor_sync(0xffffffff, v, off);
    }
    return v;
}

__global__ void softmax_bf16_to_f32_kernel(
    const __nv_bfloat16* __restrict__ input,
    float* __restrict__ output,
    int64_t N
) {
    int64_t row = blockIdx.x;
    const __nv_bfloat16* in_row = input + row * N;
    float* out_row = output + row * N;

    int tid = threadIdx.x;
    int bsz = blockDim.x;

    float local_max = -INFINITY;
    for (int64_t i = tid; i < N; i += bsz) {
        float v = __bfloat162float(in_row[i]);
        if (v > local_max) local_max = v;
    }

    __shared__ float sdata[32];
    int lane = tid & 31;
    int wid = tid >> 5;
    local_max = warp_reduce_max(local_max);
    if (lane == 0) sdata[wid] = local_max;
    __syncthreads();
    int nw = (bsz + 31) / 32;
    if (tid < 32) {
        float v = (tid < nw) ? sdata[tid] : -INFINITY;
        v = warp_reduce_max(v);
        if (tid == 0) sdata[0] = v;
    }
    __syncthreads();
    float row_max = sdata[0];

    float local_sum = 0.f;
    for (int64_t i = tid; i < N; i += bsz) {
        float v = __bfloat162float(in_row[i]);
        float e = __expf(v - row_max);
        out_row[i] = e;
        local_sum += e;
    }

    local_sum = warp_reduce_sum(local_sum);
    if (lane == 0) sdata[wid] = local_sum;
    __syncthreads();
    if (tid < 32) {
        float v = (tid < nw) ? sdata[tid] : 0.f;
        v = warp_reduce_sum(v);
        if (tid == 0) sdata[0] = v;
    }
    __syncthreads();
    float row_sum = sdata[0];
    float inv = 1.f / row_sum;

    for (int64_t i = tid; i < N; i += bsz) {
        out_row[i] = out_row[i] * inv;
    }
}

template <typename T, typename OutT>
__global__ void softmax_generic_kernel(
    const T* __restrict__ input,
    OutT* __restrict__ output,
    int64_t N
) {
