            input.data_ptr<at::Half>(), output.data_ptr<at::Half>(), N);
    } else if (in_dtype == at::kHalf && out_dtype == at::kFloat) {
        softmax_generic_kernel<at::Half, float><<<blocks, tpb>>>(
            input.data_ptr<at::Half>(), output.data_ptr<float>(), N);
    } else if (in_dtype == at::kBFloat16 && out_dtype == at::kBFloat16) {
        softmax_generic_kernel<at::BFloat16, at::BFloat16><<<blocks, tpb>>>(
            input.data_ptr<at::BFloat16>(), output.data_ptr<at::BFloat16>(), N);
    } else if (in_dtype == at::kFloat && out_dtype == at::kDouble) {
        softmax_generic_kernel<float, double><<<blocks, tpb>>>(
            input.data_ptr<float>(), output.data_ptr<double>(), N);
    } else {
        TORCH_CHECK(false, "unsupported dtype combination");
    }

    cudaError_t err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));
