#include <cuda.h>
#include <cuda_runtime.h>
#include <torch/extension.h>
#include <c10/util/Optional.h>
#include <c10/util/BFloat16.h>
#include <c10/util/Half.h>

template <typename T>
__global__ void embedding_kernel(
    T* __restrict__ output,
    const T* __restrict__ weight,
    const int64_t* __restrict__ indices,
    int64_t num_indices,
    int64_t embed_dim,
    int64_t num_embeddings)
{
    int64_t row = blockIdx.y;
    if (row >= num_indices) return;

    int64_t idx = indices[row];
    T* out_ptr = output + row * embed_dim;

    int64_t col_start = (int64_t)blockIdx.x * blockDim.x + threadIdx.x;
    int64_t stride = (int64_t)gridDim.x * blockDim.x;

    if (idx < 0 || idx >= num_embeddings) {
        for (int64_t c = col_start; c < embed_dim; c += stride) {
            out_ptr[c] = T(0);
        }
        return;
    }

    const T* w_ptr = weight + idx * embed_dim;
    for (int64_t c = col_start; c < embed_dim; c += stride) {
        out_ptr[c] = w_ptr[c];
    }
}

torch::Tensor launch(
    torch::Tensor input,
    torch::Tensor weight,
    int64_t padding_idx,
    c10::optional<double> max_norm,
    double norm_type,
    bool scale_grad_by_freq,
    bool sparse)
{
    TORCH_CHECK(input.is_cuda(), "input must be a CUDA tensor");
    TORCH_CHECK(weight.is_cuda(), "weight must be a CUDA tensor");
    TORCH_CHECK(weight.dim() == 2, "weight must be 2D");
    TORCH_CHECK(input.scalar_type() == torch::kInt64, "input must be int64");

    auto input_c = input.contiguous();
    auto weight_c = weight.contiguous();

    int64_t num_embeddings = weight_c.size(0);
    int64_t embed_dim = weight_c.size(1);

    std::vector<int64_t> out_shape;
    for (int i = 0; i < input_c.dim(); ++i) {
        out_shape.push_back(input_c.size(i));
    }
    out_shape.push_back(embed_dim);

    auto output = torch::empty(out_shape, weight_c.options());

    int64_t num_indices = input_c.numel();
    if (num_indices == 0) {
        return output;
    }

